import{c as t,Q as r,j as a,m as i}from"./chunks/framework.ByJJFMw8.js";const f=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/overview.md","filePath":"en/guide/overview.md","lastUpdated":1782204436000}'),o={name:"en/guide/overview.md"};function s(n,e,d,l,c,p){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><div class="doc-kicker">One Component, One Line, Fast Integration</div><p class="doc-lead"> Flyfish Viewer is a modular, offline-first file preview ecosystem for product teams that need reliable attachment preview inside real web applications. </p><h2 id="what-it-solves" tabindex="-1">What It Solves <a class="header-anchor" href="#what-it-solves" aria-label="Permalink to &quot;What It Solves&quot;">​</a></h2><p>Flyfish Viewer lets users preview business attachments without downloading every file or sending private documents to a conversion backend. It covers Office documents, PDF/OFD, Typst, CAD, EDA, archives, email, diagrams, mind maps, 3D, media, code, and structured data through lazy renderer packages.</p><p>The current registry declares <strong>206 extensions</strong> across <strong>24 preview pipelines</strong>.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>@file-viewer/core</code></td><td>Framework-neutral contracts, renderer registry, events, assets, lifecycle, search, zoom, print, export, and shared utilities</td></tr><tr><td>Renderer packages</td><td>Heavy format-specific engines such as PDF, Word, Presentation, CAD, Typst, Archive, Email, EPUB, Drawing, Data, and EDA</td></tr><tr><td>Presets</td><td>Product-shaped renderer bundles: <code>preset-lite</code>, <code>preset-office</code>, <code>preset-engineering</code>, and <code>preset-all</code></td></tr><tr><td>Component packages</td><td>Native integrations for Vanilla JS / Web Component, Vue, React, Svelte, and jQuery</td></tr><tr><td>Apps</td><td>Official site, documentation site, main demo, comparison demo, and component demos</td></tr></tbody></table><p>Core stays pure TypeScript and framework-neutral. Component packages depend on core and expose native APIs for their ecosystem.</p><h2 id="why-modular" tabindex="-1">Why Modular <a class="header-anchor" href="#why-modular" aria-label="Permalink to &quot;Why Modular&quot;">​</a></h2><p>Most products do not need every heavy engine on first load. Install a minimal renderer set for a focused product, or use a preset when you need broader coverage. Worker, WASM, font, and vendor assets remain self-hostable for intranet and strict-CSP deployments.</p><p>In Vite projects, <code>@file-viewer/vite-plugin</code> is the recommended assembly layer. It auto-discovers installed <code>@file-viewer/preset-*</code> packages and injects the matching capability registry, so the default setup is still <code>fileViewerRenderers({ copyAssets:true })</code>. Use <code>@file-viewer/preset-all</code> for the fastest full-capability start, or explicit <code>formats</code>, <code>renderers</code>, <code>scan:true</code>, and <code>inject:false</code> only when a product needs strict bundle control.</p><h2 id="main-entry-points" tabindex="-1">Main Entry Points <a class="header-anchor" href="#main-entry-points" aria-label="Permalink to &quot;Main Entry Points&quot;">​</a></h2><ul><li>Official site: <a href="https://file-viewer.app" target="_blank" rel="noreferrer">file-viewer.app</a></li><li>Documentation: <a href="https://doc.file-viewer.app" target="_blank" rel="noreferrer">doc.file-viewer.app</a></li><li>Live demo: <a href="https://demo.file-viewer.app" target="_blank" rel="noreferrer">demo.file-viewer.app</a></li><li>Comparison demo: <a href="https://demo.file-viewer.app/compare.html" target="_blank" rel="noreferrer">demo.file-viewer.app/compare.html</a></li><li>GitHub: <a href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">github.com/flyfish-dev/file-viewer</a></li></ul>',14)])])}const m=t(o,[["render",s]]);export{f as __pageData,m as default};
